import './productos.css';
import data from "./data-json/data.json"

function Productos() {
  return (
    data.map((elemento) => {


      <div className='producto'>
        <img src={elemento.img} alt={elemento.titulo} />
        <h3>{elemento.titulo}</h3>

        <button>Ver Mas</button>
      </div>
    })
  )
}

export default Productos;
